MT::Combinatorics c(N, mod);
void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	string s; cin >> s; s = ' ' + s;

	var C = [&](ll n, ll m)->ll {
		if (n == 0)return 1;
		if (m == 0)return 0;
		return c.C(n + m - 1, m - 1);
		};

	ll ans = 0;

	ll tot1 = 0, tot0 = 0;
	ll cnt1 = 0, cnt0 = 0;
	if (s[1] == '0')cnt1++;
	else cnt0++;

	fa(i, 1, n + m - 1) {
		if (s[i] == '0')tot0++;
		else tot1++;

     	 // 期待下一个字符 s[i+1]，新增对应的失败盒子
		if (s[i + 1] == '0')cnt1++;
		else cnt0++;

		if (n < tot1 or m < tot0)continue;
		ll left1 = n - tot1, left0 = m - tot0;
		ans = (ans + i * C(left1, cnt1) % mod * C(left0, cnt0) % mod) % mod;
	}

	if (s[n + m] == '0')tot0++;
	else tot1++;
	if (tot1 == n and tot0 == m)ans += n + m;

	cout << ans << endl;
	return;
}
